-- 1. Update existing venues to 2 US and 2 VN.
-- US Venues
UPDATE venue
SET name = 'Madison Square Garden', city = 'New York', country = 'US', latitude = 40.750504, longitude = -73.9934
WHERE id = '018f4e1a-0003-4000-8000-000000000001';

UPDATE venue
SET name = 'Staples Center', city = 'Los Angeles', country = 'US', latitude = 34.043017, longitude = -118.267254
WHERE id = '018f4e1a-0004-4000-8000-000000000001';

-- VN Venues (Keep Hanoi Opera House and Phu Tho)
UPDATE venue
SET name = 'Nhà thi đấu Phú Thọ', city = 'TP. Hồ Chí Minh', country = 'VN'
WHERE id = '018f4e1a-0005-4000-8000-000000000001';

-- Hanoi Opera House remains at 018f4e1a-0006-4000-8000-000000000001

